package com.dataprocessing.grpc;

import com.google.protobuf.ByteString;
import io.grpc.ManagedChannel;
import io.grpc.netty.shaded.io.grpc.netty.NettyChannelBuilder;
import io.grpc.stub.StreamObserver;

import java.io.*;
import java.nio.file.*;
import java.util.UUID;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicLong;
import java.util.logging.Level;
import java.util.logging.Logger;

public class FileServiceClient {
    private static final Logger logger = Logger.getLogger(FileServiceClient.class.getName());
    private static final int CHUNK_SIZE = 64 * 1024; // 64KB
    private static final int MAX_MESSAGE_SIZE = 256 * 1024 * 1024; // 256MB

    private final ManagedChannel channel;
    private final FileServiceGrpc.FileServiceBlockingStub blockingStub;
    private final FileServiceGrpc.FileServiceStub asyncStub;

    public FileServiceClient(String host, int port) {
        channel = NettyChannelBuilder.forAddress(host, port)
                .usePlaintext()
                .maxInboundMessageSize(MAX_MESSAGE_SIZE)
                .keepAliveTime(5, TimeUnit.MINUTES)
                .keepAliveTimeout(20, TimeUnit.SECONDS)
                .keepAliveWithoutCalls(true)
                .build();

        blockingStub = FileServiceGrpc.newBlockingStub(channel);
        asyncStub = FileServiceGrpc.newStub(channel);
    }

    /**
     * Upload a file using client streaming.
     */
    public void uploadFile(String filePath) throws InterruptedException, IOException {
        Path path = Paths.get(filePath);
        if (!Files.exists(path)) {
            logger.severe("File not found: " + filePath);
            return;
        }

        long fileSize = Files.size(path);
        String filename = path.getFileName().toString();
        CountDownLatch finishLatch = new CountDownLatch(1);

        StreamObserver<UploadStatus> responseObserver = new StreamObserver<UploadStatus>() {
            @Override
            public void onNext(UploadStatus status) {
                logger.info(String.format("Upload result: success=%b, message=%s, bytes=%d, fileId=%s",
                        status.getSuccess(), status.getMessage(),
                        status.getBytesReceived(), status.getFileId()));
            }

            @Override
            public void onError(Throwable t) {
                logger.log(Level.SEVERE, "Upload failed", t);
                finishLatch.countDown();
            }

            @Override
            public void onCompleted() {
                logger.info("Upload stream completed");
                finishLatch.countDown();
            }
        };

        StreamObserver<FileChunk> requestObserver = asyncStub.uploadFile(responseObserver);

        try (InputStream inputStream = new BufferedInputStream(new FileInputStream(path.toFile()), 256 * 1024)) {
            byte[] buffer = new byte[CHUNK_SIZE];
            int bytesRead;
            long offset = 0;

            while ((bytesRead = inputStream.read(buffer)) != -1) {
                FileChunk chunk = FileChunk.newBuilder()
                        .setFilename(filename)
                        .setContent(ByteString.copyFrom(buffer, 0, bytesRead))
                        .setOffset(offset)
                        .setTotalSize(fileSize)
                        .putMetadata("content-type", guessContentType(filename))
                        .build();

                requestObserver.onNext(chunk);
                offset += bytesRead;

                // Check for errors
                if (finishLatch.getCount() == 0) {
                    logger.warning("Stream completed prematurely");
                    return;
                }
            }

            requestObserver.onCompleted();
        } catch (RuntimeException e) {
            requestObserver.onError(e);
            throw e;
        }

        if (!finishLatch.await(5, TimeUnit.MINUTES)) {
            logger.warning("Upload did not finish within timeout");
        }
    }

    /**
     * Download a file using server streaming.
     */
    public void downloadFile(String filename, String outputPath) throws InterruptedException {
        FileRequest request = FileRequest.newBuilder()
                .setFilename(filename)
                .setOffset(0)
                .setLength(0) // 0 means entire file
                .build();

        CountDownLatch finishLatch = new CountDownLatch(1);
        AtomicLong totalReceived = new AtomicLong(0);

        asyncStub.downloadFile(request, new StreamObserver<FileChunk>() {
            private OutputStream outputStream;

            @Override
            public void onNext(FileChunk chunk) {
                try {
                    if (outputStream == null) {
                        outputStream = new BufferedOutputStream(
                                new FileOutputStream(outputPath), 256 * 1024);
                        logger.info(String.format("Downloading file: %s, totalSize=%d",
                                chunk.getFilename(), chunk.getTotalSize()));
                    }

                    byte[] content = chunk.getContent().toByteArray();
                    outputStream.write(content);
                    long received = totalReceived.addAndGet(content.length);

                    if (received % (10 * 1024 * 1024) == 0) {
                        logger.info(String.format("Download progress: %d/%d bytes",
                                received, chunk.getTotalSize()));
                    }
                } catch (IOException e) {
                    logger.log(Level.SEVERE, "Error writing downloaded chunk", e);
                }
            }

            @Override
            public void onError(Throwable t) {
                logger.log(Level.SEVERE, "Download failed", t);
                closeStream();
                finishLatch.countDown();
            }

            @Override
            public void onCompleted() {
                closeStream();
                logger.info(String.format("Download complete: %d bytes received", totalReceived.get()));
                finishLatch.countDown();
            }

            private void closeStream() {
                if (outputStream != null) {
                    try {
                        outputStream.flush();
                        outputStream.close();
                    } catch (IOException e) {
                        logger.log(Level.WARNING, "Error closing output stream", e);
                    }
                }
            }
        });

        if (!finishLatch.await(5, TimeUnit.MINUTES)) {
            logger.warning("Download did not finish within timeout");
        }
    }

    /**
     * Bidirectional streaming for real-time data processing.
     */
    public void processDataBidirectional(int messageCount) throws InterruptedException {
        CountDownLatch finishLatch = new CountDownLatch(1);
        AtomicLong responsesReceived = new AtomicLong(0);

        StreamObserver<DataMessage> responseObserver = new StreamObserver<DataMessage>() {
            @Override
            public void onNext(DataMessage response) {
                long count = responsesReceived.incrementAndGet();
                logger.info(String.format("Received response %d: type=%s, id=%s, size=%d",
                        count, response.getType(), response.getMessageId(),
                        response.getPayload().size()));
            }

            @Override
            public void onError(Throwable t) {
                logger.log(Level.SEVERE, "Bidirectional stream error", t);
                finishLatch.countDown();
            }

            @Override
            public void onCompleted() {
                logger.info(String.format("Bidirectional stream completed. Total responses: %d",
                        responsesReceived.get()));
                finishLatch.countDown();
            }
        };

        StreamObserver<DataMessage> requestObserver = asyncStub.processData(responseObserver);

        try {
            String[] messageTypes = {"TRANSFORM", "VALIDATE", "AGGREGATE", "COMPRESS", "ECHO"};

            for (int i = 0; i < messageCount; i++) {
                String type = messageTypes[i % messageTypes.length];
                String payload = String.format("Test data payload #%d - timestamp: %d - %s",
                        i, System.currentTimeMillis(), UUID.randomUUID());

                DataMessage message = DataMessage.newBuilder()
                        .setMessageId(UUID.randomUUID().toString())
                        .setType(type)
                        .setPayload(ByteString.copyFromUtf8(payload))
                        .putHeaders("client-id", "data-processor-client-1")
                        .putHeaders("sequence", String.valueOf(i))
                        .putHeaders("encoding", "UTF-8")
                        .setTimestamp(System.currentTimeMillis())
                        .build();

                requestObserver.onNext(message);

                // Small delay to simulate real processing
                if (i % 10 == 0) {
                    Thread.sleep(10);
                }

                if (finishLatch.getCount() == 0) {
                    logger.warning("Stream terminated by server");
                    return;
                }
            }

            requestObserver.onCompleted();
        } catch (RuntimeException e) {
            requestObserver.onError(e);
            throw e;
        }

        if (!finishLatch.await(5, TimeUnit.MINUTES)) {
            logger.warning("Bidirectional processing did not finish within timeout");
        }
    }

    public void shutdown() throws InterruptedException {
        channel.shutdown().awaitTermination(10, TimeUnit.SECONDS);
    }

    private String guessContentType(String filename) {
        if (filename.endsWith(".json")) return "application/json";
        if (filename.endsWith(".xml")) return "application/xml";
        if (filename.endsWith(".csv")) return "text/csv";
        if (filename.endsWith(".txt")) return "text/plain";
        if (filename.endsWith(".bin")) return "application/octet-stream";
        if (filename.endsWith(".gz")) return "application/gzip";
        return "application/octet-stream";
    }

    // Demo entry point
    public static void main(String[] args) throws Exception {
        FileServiceClient client = new FileServiceClient("localhost", 50051);

        try {
            // Demo: Upload a file
            if (args.length > 0 && "upload".equals(args[0])) {
                String filePath = args.length > 1 ? args[1] : "/tmp/test-upload.bin";
                logger.info("=== Starting file upload ===");
                client.uploadFile(filePath);
            }

            // Demo: Download a file
            if (args.length > 0 && "download".equals(args[0])) {
                String filename = args.length > 1 ? args[1] : "test-upload.bin";
                String outputPath = args.length > 2 ? args[2] : "/tmp/test-download.bin";
                logger.info("=== Starting file download ===");
                client.downloadFile(filename, outputPath);
            }

            // Demo: Bidirectional processing
            if (args.length == 0 || "process".equals(args[0])) {
                int count = args.length > 1 ? Integer.parseInt(args[1]) : 50;
                logger.info("=== Starting bidirectional data processing ===");
                client.processDataBidirectional(count);
            }

        } finally {
            client.shutdown();
        }
    }
}

// === FlowControlInterceptor.java ===

package com.dataprocessing.grpc;

import io.grpc.*;

import java.util.logging.Logger;

public class FlowControlInterceptor implements ServerInterceptor {
    private static final Logger logger = Logger.getLogger(FlowControlInterceptor.class.getName());

    @Override
    public <ReqT, RespT> ServerCall.Listener<ReqT> interceptCall(
            ServerCall<ReqT, RespT> call,
            Metadata headers,
            ServerCallHandler<ReqT, RespT> next) {

        String methodName = call.getMethodDescriptor().getFullMethodName();
        long startTime = System.currentTimeMillis();

        logger.info("gRPC call started: " + methodName);

        ServerCall<ReqT, RespT> wrappedCall = new ForwardingServerCall.SimpleForwardingServerCall<ReqT, RespT>(call) {
            @Override
            public void close(Status status, Metadata trailers) {
                long duration = System.currentTimeMillis() - startTime;
                logger.info(String.format("gRPC call completed: %s, status=%s, duration=%dms",
                        methodName, status.getCode(), duration));
                super.close(status, trailers);
            }
        };

        return next.startCall(wrappedCall, headers);
    }
}

